16	export function nextGeneration(cells: readonly Cell[]): Cell[] {
17	  const alive = new Set(cells.map(key));
18	  const neighborCounts = new Map<string, { cell: Cell; count: number }>();
19	  for (const cell of cells) {
20	    for (const n of neighborsOf(cell)) {
21	      const k = key(n);
22	      const entry = neighborCounts.get(k);
23	      if (entry) entry.count++;
24	      else neighborCounts.set(k, { cell: n, count: 1 });
25	    }
26	  }
27	  const next: Cell[] = [];
28	  for (const [k, { cell, count }] of neighborCounts) {
29	    if (alive.has(k) ? count === 2 || count === 3 : count === 3) {
30	      next.push(cell);
31	    }
32	  }
33	  return next;
34	}
